// ======================================
// Vacatory: weekly commercial news scan (Playwright edition)
//
// Uses a real headless browser (Chromium via Playwright) to load each
// firm's news/insights page, so JavaScript-rendered pages work just as
// well as plain HTML ones — this matters a lot here, since several firms'
// news pages are built on client-side-rendered CMS platforms and would
// return an empty shell to a plain fetch() request. Every firm gets a
// fair shot at being scraped the same way, rather than some firms
// systematically dropping out because of their site's tech stack.
//
// Requires env vars:
//   SUPABASE_URL
//   SUPABASE_SERVICE_ROLE_KEY   (service role key — bypasses RLS; never
//                                 expose this in client-side code)
// ======================================

import { chromium } from "playwright";
import { createClient } from "@supabase/supabase-js";
import * as cheerio from "cheerio";
import { readFileSync } from "fs";
import { fileURLToPath } from "url";
import { dirname, join } from "path";

const __dirname = dirname(fileURLToPath(import.meta.url));

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) {
  console.error("Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY environment variables.");
    process.exit(1);
    }

    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

    const MAX_ITEMS_PER_FIRM = 8;
    const PAGE_TIMEOUT_MS = 30000;
    const USER_AGENT =
      "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36 VacatoryNewsBot/1.0 (+https://vacatory.com)";

      const sources = JSON.parse(
        readFileSync(join(__dirname, "firm-news-sources.json"), "utf-8")
        );

        // ---------- Rendering ----------

        async function fetchRenderedHtml(browser, url) {
          const context = await browser.newContext({ userAgent: USER_AGENT });
            const page = await context.newPage();
              try {
                  await page.goto(url, { timeout: PAGE_TIMEOUT_MS, waitUntil: "domcontentloaded" });
                      // Give client-side rendering a moment to finish populating the DOM.
                          // "networkidle" is more thorough but some analytics-heavy pages never
                              // truly go idle, so cap it and fall back to a fixed wait either way.
                                  try {
                                        await page.waitForLoadState("networkidle", { timeout: 8000 });
                                            } catch {
                                                  // fine — continue with whatever has rendered so far
                                                      }
                                                          await page.waitForTimeout(1500);
                                                              return await page.content();
                                                                } finally {
                                                                    await context.close();
                                                                      }
                                                                      }

                                                                      // ---------- Extraction (same heuristic approach as before, now running
                                                                      // against fully-rendered HTML rather than the raw server response) ----------

                                                                      function extractArticles(html, baseUrl) {
                                                                        const $ = cheerio.load(html);
                                                                          const candidates = [];

                                                                            const selectors = [
                                                                                "article",
                                                                                    "[class*='news-item']",
                                                                                        "[class*='newsitem']",
                                                                                            "[class*='insight-card']",
                                                                                                "[class*='insight-item']",
                                                                                                    "[class*='teaser']",
                                                                                                        "[class*='listing-item']",
                                                                                                            "[class*='card']",
                                                                                                                "li[class*='result']",
                                                                                                                  ];
                                                                                                                  
                                                                                                                    const seenEls = new Set();
                                                                                                                    
                                                                                                                      for (const sel of selectors) {
                                                                                                                          $(sel).each((_, el) => {
                                                                                                                                if (seenEls.has(el)) return;
                                                                                                                                      seenEls.add(el);
                                                                                                                                      
                                                                                                                                            const $el = $(el);
                                                                                                                                                  const $link = $el.find("a[href]").first();
                                                                                                                                                        if (!$link.length) return;
                                                                                                                                                        
                                                                                                                                                              let href = $link.attr("href") || "";
                                                                                                                                                                    if (!href || href.startsWith("#") || href.startsWith("mailto:") || href.startsWith("javascript:")) return;
                                                                                                                                                                    
                                                                                                                                                                          try {
                                                                                                                                                                                  href = new URL(href, baseUrl).toString();
                                                                                                                                                                                        } catch {
                                                                                                                                                                                                return;
                                                                                                                                                                                                      }
                                                                                                                                                                                                      
                                                                                                                                                                                                            let headline =
                                                                                                                                                                                                                    $el.find("h1,h2,h3,h4").first().text().trim() ||
                                                                                                                                                                                                                            $link.text().trim() ||
                                                                                                                                                                                                                                    $el.attr("aria-label") ||
                                                                                                                                                                                                                                            "";
                                                                                                                                                                                                                                                  headline = headline.replace(/\s+/g, " ").trim();
                                                                                                                                                                                                                                                        if (!headline || headline.length < 8) return;
                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                              const timeEl = $el.find("time").first();
                                                                                                                                                                                                                                                                    let publishedDate = timeEl.attr("datetime") || timeEl.text().trim() || null;
                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                          const summary =
                                                                                                                                                                                                                                                                                  $el.find("p").first().text().trim().replace(/\s+/g, " ").slice(0, 280) || null;
                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                        candidates.push({ headline, url: href, publishedDate, summary });
                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                if (candidates.length >= MAX_ITEMS_PER_FIRM) break;
                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                    const seenUrls = new Set();
                                                                                                                                                                                                                                                                                                      const deduped = [];
                                                                                                                                                                                                                                                                                                        for (const c of candidates) {
                                                                                                                                                                                                                                                                                                            if (seenUrls.has(c.url)) continue;
                                                                                                                                                                                                                                                                                                                seenUrls.add(c.url);
                                                                                                                                                                                                                                                                                                                    deduped.push(c);
                                                                                                                                                                                                                                                                                                                        if (deduped.length >= MAX_ITEMS_PER_FIRM) break;
                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                            return deduped;
                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                            function normalizeDate(raw) {
                                                                                                                                                                                                                                                                                                                              if (!raw) return null;
                                                                                                                                                                                                                                                                                                                                const parsed = new Date(raw);
                                                                                                                                                                                                                                                                                                                                  if (isNaN(parsed.getTime())) return null;
                                                                                                                                                                                                                                                                                                                                    return parsed.toISOString().slice(0, 10);
                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                    // ---------- Main ----------
                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                    async function main() {
                                                                                                                                                                                                                                                                                                                                      const { data: firms, error: firmsError } = await supabase.from("firms").select("id, name");
                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                        if (firmsError) {
                                                                                                                                                                                                                                                                                                                                            console.error("Failed to load firms from Supabase:", firmsError.message);
                                                                                                                                                                                                                                                                                                                                                process.exit(1);
                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                    const firmsByName = new Map(firms.map((f) => [f.name, f]));
                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                      const summary = {
                                                                                                                                                                                                                                                                                                                                                          inserted: 0,
                                                                                                                                                                                                                                                                                                                                                              noItemsFound: [],
                                                                                                                                                                                                                                                                                                                                                                  fetchFailed: [],
                                                                                                                                                                                                                                                                                                                                                                      noSourceConfigured: [],
                                                                                                                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                          const browser = await chromium.launch();
                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                                for (const [firmName, source] of Object.entries(sources)) {
                                                                                                                                                                                                                                                                                                                                                                                      if (firmName === "_comment") continue;
                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                            const firm = firmsByName.get(firmName);
                                                                                                                                                                                                                                                                                                                                                                                                  if (!firm) {
                                                                                                                                                                                                                                                                                                                                                                                                          summary.noSourceConfigured.push(firmName);
                                                                                                                                                                                                                                                                                                                                                                                                                  continue;
                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                              let html;
                                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                                            html = await fetchRenderedHtml(browser, source.url);
                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                          summary.fetchFailed.push({ firm: firmName, url: source.url, error: err.message });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  continue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const articles = extractArticles(html, source.url);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (articles.length === 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            summary.noItemsFound.push({ firm: firmName, url: source.url, confidence: source.confidence });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    continue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                for (const article of articles) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const row = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  firm_id: firm.id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            headline: article.headline,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      summary: article.summary,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                url: article.url,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          published_date:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      normalizeDate(article.publishedDate) || new Date().toISOString().slice(0, 10),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const { error: insertError } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .from("commercial_news")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .upsert(row, { onConflict: "firm_id,url", ignoreDuplicates: true });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (insertError) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            console.error(`Insert failed for ${firmName} — ${article.url}:`, insertError.message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              summary.inserted += 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  console.log(`✓ ${firmName}: ${articles.length} article(s) found`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } finally {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await browser.close();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // ---------- Print run summary ----------
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  console.log("\n=== Commercial news scan summary ===");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    console.log(`Rows inserted/updated: ${summary.inserted}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (summary.noSourceConfigured.length) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          console.log(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                `\nFirms with a news URL configured but no matching row in the firms table (${summary.noSourceConfigured.length}):`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        summary.noSourceConfigured.forEach((f) => console.log(`  - ${f}`));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (summary.fetchFailed.length) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                console.log(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      `\nFirms whose news page failed to load (${summary.fetchFailed.length}) — check the URL is still correct:`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              summary.fetchFailed.forEach((f) => console.log(`  - ${f.firm}: ${f.url} (${f.error})`));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (summary.noItemsFound.length) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      console.log(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            `\nFirms whose page loaded but no articles were found (${summary.noItemsFound.length}) — likely a selector mismatch that needs a firm-specific fix:`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    summary.noItemsFound.forEach((f) => console.log(`  - ${f.firm} [${f.confidence}]: ${f.url}`));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const totalFirms = Object.keys(sources).length - 1; // minus _comment
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const firmsWithNoCoverage = summary.fetchFailed.length + summary.noItemsFound.length;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            console.log(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                `\n${totalFirms - firmsWithNoCoverage} of ${totalFirms} firms returned at least one article this run.`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Exit with a non-zero code if a large share of firms got no coverage,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // so a GitHub Actions failure notification actually surfaces the problem
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // instead of it silently going unnoticed.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (firmsWithNoCoverage > totalFirms * 0.3) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.error(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "\nMore than 30% of firms returned no articles this run — treating this as a failure so it doesn't go unnoticed."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            process.exitCode = 1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                console.log("\nDone.");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                main().catch((err) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  console.error("Fatal error running commercial news scan:", err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    process.exit(1);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
